            "print(f'Train: {len(X_train)}, Val: {len(X_val)}, Test: {len(X_test)}')\nprint(f'Class balance — Train: {y_train.mean():.3f}, Val: {y_val.mean():.3f}, Test: {y_test.mean():.3f}')",
